Restart a spoke container, preserving its filesystem.
   pub async fn restart(&self, spoke_name: &str) -> Result<()> {
       let span = info_span!("corvia.spoke.restart", spoke_name);
       self.restart_inner(spoke_name).instrument(span).await
   }

   async fn restart_inner(&self, spoke_name: &str) -> Result<()> {
       self.docker
           .stop_container(spoke_name, Some(StopContainerOptions { t: Some(10), signal: None }))
           .await
           .map_err(|e| {
               CorviaError::Docker(format!("Failed to stop spoke '{spoke_name}': {e}"))
           })?;

       self.docker
           .start_container(spoke_name, None::<StartContainerOptions>)
           .await
           .map_err(|e| {
               CorviaError::Docker(format!("Failed to restart spoke '{spoke_name}': {e}"))
           })?;

       info!(spoke_name, "Spoke restarted");
       Ok(())
   }

   /// Prune exited spoke containers whose creation time exceeds the given threshold.
   ///
   /// Note: uses the container's `Created` timestamp, not its exit time, because
   /// the Docker list API does not expose `FinishedAt`. A container created 2h ago
   /// that just exited will be pruned if the threshold is 1h. This is acceptable
   /// because spoke containers are single-use (one dev-loop run) and are not
   /// expected to run for longer than the prune threshold.
   /// Returns the names of pruned containers.
   pub async fn prune(&self, max_age: std::time::Duration) -> Result<Vec<String>> {
       let span = info_span!("corvia.spoke.prune", max_age_secs = max_age.as_secs());
       self.prune_inner(max_age).instrument(span).await
   }
